#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <stdint.h>
#include <math_constants.h>

static_assert(GQA_NUM_Q_HEADS == 32, "fixed spec");
static_assert(GQA_NUM_KV_HEADS == 8, "fixed spec");
static_assert(GQA_HEAD_DIM == 128, "fixed spec");
static_assert(GQA_PAGE_SIZE == 1, "fixed spec");

__device__ __forceinline__ float warp_reduce_max(float v) {
  for (int offset = 16; offset > 0; offset >>= 1) {
    v = fmaxf(v, __shfl_down_sync(0xffffffffu, v, offset));
  }
  return v;
}
__device__ __forceinline__ float warp_reduce_sum(float v) {
  for (int offset = 16; offset > 0; offset >>= 1) {
    v += __shfl_down_sync(0xffffffffu, v, offset);
  }
  return v;
}

// blockDim.x == 256
__device__ __forceinline__ float block_reduce_max_256(float v) {
  __shared__ float smem[8];  // 8 warps
  const int lane = threadIdx.x & 31;
  const int warp = threadIdx.x >> 5;
  v = warp_reduce_max(v);
  if (lane == 0) smem[warp] = v;
  __syncthreads();
  float out = (threadIdx.x < 8) ? smem[lane] : -CUDART_INF_F;
  if (warp == 0) out = warp_reduce_max(out);
  out = __shfl_sync(0xffffffffu, out, 0);
  return out;
}

// blockDim.x == 256
__device__ __forceinline__ float block_reduce_sum_256(float v) {
  __shared__ float smem[8];
  const int lane = threadIdx.x & 31;
  const int warp = threadIdx.x >> 5;
  v = warp_reduce_sum(v);
  if (lane == 0) smem[warp] = v;
  __syncthreads();
  float out = (threadIdx.x < 8) ? smem[lane] : 0.0f;
  if (warp == 0) out = warp_reduce_sum(out);
  out = __shfl_sync(0xffffffffu, out, 0);
  return out;
}

// Grid: (B, 32)
// Block: 256 threads
__global__ void gqa_paged_decode_h32_kv8_d128_ps1_kernel(
    const __nv_bfloat16* __restrict__ q,        // [B,32,128]
    const __nv_bfloat16* __restrict__ k_cache,  // [P,1,8,128]
    const __nv_bfloat16* __restrict__ v_cache,  // [P,1,8,128]
    const int32_t* __restrict__ kv_indptr,      // [B+1]
    const int32_t* __restrict__ kv_indices,     // [nnz]
    float sm_scale,
    __nv_bfloat16* __restrict__ out,            // [B,32,128]
    float* __restrict__ lse,                    // [B,32] base-2 logsumexp
    int32_t batch_size) {
  const int b = (int)blockIdx.x;
  const int h = (int)blockIdx.y;
  const int tid = (int)threadIdx.x;
  if (b >= batch_size) return;

  const int32_t start = kv_indptr[b];
  const int32_t end = kv_indptr[b + 1];
  const int32_t ntok = end - start;

  const int64_t q_base = ((int64_t)b * GQA_NUM_Q_HEADS + h) * (int64_t)GQA_HEAD_DIM;
  const int64_t o_base = q_base;
  const int64_t lse_idx = (int64_t)b * GQA_NUM_Q_HEADS + h;

  if (ntok <= 0) {
    for (int d = tid; d < GQA_HEAD_DIM; d += (int)blockDim.x) {
      out[o_base + d] = __float2bfloat16_rn(0.0f);
    }
    if (tid == 0) lse[lse_idx] = -CUDART_INF_F;
    return;
  }

  const int kv_head = h / GQA_GQA_RATIO;  // 0..7

  // Q in shared memory
  __shared__ float q_smem[GQA_HEAD_DIM];
  for (int d = tid; d < GQA_HEAD_DIM; d += (int)blockDim.x) {
    q_smem[d] = __bfloat162float(q[q_base + d]);
  }
  __syncthreads();

  // Pass 1: max(logit)
  float local_max = -CUDART_INF_F;
  for (int t = tid; t < ntok; t += (int)blockDim.x) {
    const int32_t page = kv_indices[start + t];
    const int64_t k_base =
        ((int64_t)page * (int64_t)GQA_PAGE_SIZE * (int64_t)GQA_NUM_KV_HEADS +
         (int64_t)kv_head) *
        (int64_t)GQA_HEAD_DIM;

    float acc = 0.0f;
#pragma unroll
    for (int d = 0; d < GQA_HEAD_DIM; d += 8) {
      const float q0 = q_smem[d + 0];
      const float q1 = q_smem[d + 1];
      const float q2 = q_smem[d + 2];
      const float q3 = q_smem[d + 3];
      const float q4 = q_smem[d + 4];
      const float q5 = q_smem[d + 5];
      const float q6 = q_smem[d + 6];
      const float q7 = q_smem[d + 7];

      const float k0 = __bfloat162float(k_cache[k_base + d + 0]);
      const float k1 = __bfloat162float(k_cache[k_base + d + 1]);
      const float k2 = __bfloat162float(k_cache[k_base + d + 2]);
      const float k3 = __bfloat162float(k_cache[k_base + d + 3]);
      const float k4 = __bfloat162float(k_cache[k_base + d + 4]);
      const float k5 = __bfloat162float(k_cache[k_base + d + 5]);
      const float k6 = __bfloat162float(k_cache[k_base + d + 6]);
      const float k7 = __bfloat162float(k_cache[k_base + d + 7]);

      acc = fmaf(q0, k0, acc);
      acc = fmaf(q1, k1, acc);
      acc = fmaf(q2, k2, acc);
      acc = fmaf(q3, k3, acc);
      acc = fmaf(q4, k4, acc);
      acc = fmaf(q5, k5, acc);
      acc = fmaf(q6, k6, acc);
      acc = fmaf(q7, k7, acc);
    }
    local_max = fmaxf(local_max, acc * sm_scale);
  }
  const float m = block_reduce_max_256(local_max);

  // Pass 2: denom + output accumulation
  const bool has_d = (tid < GQA_HEAD_DIM);
  float outv = 0.0f;
  float local_denom = 0.0f;

  // exp(x) = exp2(x / ln2)
  const float inv_ln2 = 1.4426950408889634f;  // 1/ln(2)

#pragma unroll 1
  for (int t = 0; t < ntok; ++t) {
    const int32_t page = kv_indices[start + t];
    const int64_t kv_base =
        ((int64_t)page * (int64_t)GQA_PAGE_SIZE * (int64_t)GQA_NUM_KV_HEADS +
         (int64_t)kv_head) *
        (int64_t)GQA_HEAD_DIM;

    float acc = 0.0f;
#pragma unroll
    for (int d = 0; d < GQA_HEAD_DIM; d += 8) {
      const float q0 = q_smem[d + 0];
      const float q1 = q_smem[d + 1];
      const float q2 = q_smem[d + 2];
      const float q3 = q_smem[d + 3];
      const float q4 = q_smem[d + 4];
      const float q5 = q_smem[d + 5];
      const float q6 = q_smem[d + 6];
      const float q7 = q_smem[d + 7];

      const float k0 = __bfloat162float(k_cache[kv_base + d + 0]);
      const float k1 = __bfloat162float(k_cache[kv_base + d + 1]);
      const float k2 = __bfloat162float(k_cache[kv_base + d + 2]);
      const float k3 = __bfloat162float(k_cache[kv_base + d + 3]);
      const float k4 = __bfloat162float(k_cache[kv_base + d + 4]);
      const float k5 = __bfloat162float(k_cache[kv_base + d + 5]);
      const float k6 = __bfloat162float(k_cache[kv_base + d + 6]);
      const float k7 = __bfloat162float(k_cache[kv_base + d + 7]);

      acc = fmaf(q0, k0, acc);
      acc = fmaf(q1, k1, acc);
      acc = fmaf(q2, k2, acc);
      acc = fmaf(q3, k3, acc);
      acc = fmaf(q4, k4, acc);
      acc = fmaf(q5, k5, acc);
      acc = fmaf(q6, k6, acc);
      acc = fmaf(q7, k7, acc);
    }

    const float logit = acc * sm_scale;
    const float w = exp2f((logit - m) * inv_ln2);
    local_denom += w;

    if (has_d) {
      const float vv = __bfloat162float(v_cache[kv_base + tid]);
      outv = fmaf(w, vv, outv);
    }
  }

  const float denom = block_reduce_sum_256(local_denom);

  if (has_d) {
    out[o_base + tid] = __float2bfloat16_rn(outv / denom);
  }
  if (tid == 0) {
    // base-2 logsumexp: log2(sum(exp(logit))) = m/ln2 + log2(denom)
    lse[lse_idx] = m * inv_ln2 + log2f(denom);
  }
}

void launch_gqa_paged_decode_h32_kv8_d128_ps1(
    const __nv_bfloat16* q,
    const __nv_bfloat16* k_cache,
    const __nv_bfloat16* v_cache,
    const int32_t* kv_indptr,
    const int32_t* kv_indices,
    float sm_scale,
    __nv_bfloat16* out,
    float* lse,
    int32_t batch_size,
    cudaStream_t stream) {
  dim3 block(256, 1, 1);
  dim3 grid((unsigned)batch_size, (unsigned)GQA_NUM_Q_HEADS, 1);
  gqa_paged_decode_h32_kv8_d128_ps1_kernel<<<grid, block, 0, stream>>>(
      q, k_cache, v_cache, kv_indptr, kv_indices, sm_scale, out, lse, batch_size);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <cuda_runtime.h>
#include <cmath>
#include <sstream>
#include <stdexcept>
#include <vector>

#include "kernel.h"

static void check(bool cond, const char* msg) {
  if (!cond) throw std::runtime_error(msg);
}

static void check_cuda(cudaError_t err, const char* what) {
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << what << ": " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }
}

std::vector<torch::Tensor> run(
    torch::Tensor q,
    torch::Tensor k_cache,
    torch::Tensor v_cache,
    torch::Tensor kv_indptr,
    torch::Tensor kv_indices,
    c10::optional<torch::Tensor> sm_scale_opt) {
  check(q.defined(), "q must be defined");
  check(k_cache.defined(), "k_cache must be defined");
  check(v_cache.defined(), "v_cache must be defined");
  check(kv_indptr.defined(), "kv_indptr must be defined");
  check(kv_indices.defined(), "kv_indices must be defined");

  check(q.device().is_cuda(), "q must be a CUDA tensor");
  check(k_cache.device().is_cuda(), "k_cache must be a CUDA tensor");
  check(v_cache.device().is_cuda(), "v_cache must be a CUDA tensor");
  check(kv_indptr.device().is_cuda(), "kv_indptr must be a CUDA tensor");
  check(kv_indices.device().is_cuda(), "kv_indices must be a CUDA tensor");

  check(q.dtype() == torch::kBFloat16, "q must be torch.bfloat16");
  check(k_cache.dtype() == torch::kBFloat16, "k_cache must be torch.bfloat16");
  check(v_cache.dtype() == torch::kBFloat16, "v_cache must be torch.bfloat16");
  check(kv_indptr.dtype() == torch::kInt32, "kv_indptr must be torch.int32");
  check(kv_indices.dtype() == torch::kInt32, "kv_indices must be torch.int32");

  check(q.is_contiguous(), "q must be contiguous");
  check(k_cache.is_contiguous(), "k_cache must be contiguous");
  check(v_cache.is_contiguous(), "v_cache must be contiguous");
  check(kv_indptr.is_contiguous(), "kv_indptr must be contiguous");
  check(kv_indices.is_contiguous(), "kv_indices must be contiguous");

  check(q.dim() == 3, "q must be [batch_size, 32, 128]");
  check(k_cache.dim() == 4, "k_cache must be [num_pages, 1, 8, 128]");
  check(v_cache.dim() == 4, "v_cache must be [num_pages, 1, 8, 128]");
  check(kv_indptr.dim() == 1, "kv_indptr must be 1D");
  check(kv_indices.dim() == 1, "kv_indices must be 1D");

  const int64_t B = q.size(0);
  check(q.size(1) == GQA_NUM_Q_HEADS, "q.size(1) must be 32");
  check(q.size(2) == GQA_HEAD_DIM, "q.size(2) must be 128");

  check(k_cache.size(1) == GQA_PAGE_SIZE, "k_cache.size(1) (page_size) must be 1");
  check(k_cache.size(2) == GQA_NUM_KV_HEADS, "k_cache.size(2) must be 8");
  check(k_cache.size(3) == GQA_HEAD_DIM, "k_cache.size(3) must be 128");
  check(v_cache.sizes() == k_cache.sizes(), "v_cache must have same shape as k_cache");

  check(kv_indptr.size(0) == B + 1, "kv_indptr length must be batch_size + 1");

  // IMPORTANT: avoid .item() on CUDA tensors in sandboxed runners (pidfd_getfd).
  // Validate kv_indices length equals kv_indptr[B] by copying that int32 to host.
  int32_t nnz_expected = 0;
  cudaStream_t stream = at::cuda::getDefaultCUDAStream();
  check_cuda(cudaMemcpyAsync(&nnz_expected,
                             kv_indptr.data_ptr<int32_t>() + B,
                             sizeof(int32_t),
                             cudaMemcpyDeviceToHost,
                             stream),
             "cudaMemcpyAsync(kv_indptr[B]) failed");
  check_cuda(cudaStreamSynchronize(stream),
             "cudaStreamSynchronize after kv_indptr[B] memcpy failed");
  check((int64_t)nnz_expected == kv_indices.size(0),
        "kv_indices length must equal kv_indptr[-1]");

  float sm_scale = 1.0f / std::sqrt((float)GQA_HEAD_DIM);
  if (sm_scale_opt.has_value() && sm_scale_opt.value().defined()) {
    auto s = sm_scale_opt.value();
    check(s.numel() == 1, "sm_scale must be a scalar tensor");
    check(s.dtype() == torch::kFloat32, "sm_scale must be float32");
    if (s.device().is_cuda()) {
      float tmp = 0.0f;
      check_cuda(cudaMemcpyAsync(&tmp,
                                 s.data_ptr<float>(),
                                 sizeof(float),
                                 cudaMemcpyDeviceToHost,
                                 stream),
                 "cudaMemcpyAsync(sm_scale) failed");
      check_cuda(cudaStreamSynchronize(stream),
                 "cudaStreamSynchronize after sm_scale memcpy failed");
      sm_scale = tmp;
    } else {
      sm_scale = s.item<float>();
    }
  }

  auto out = torch::empty({B, GQA_NUM_Q_HEADS, GQA_HEAD_DIM},
                          torch::TensorOptions().device(q.device()).dtype(torch::kBFloat16));
  auto lse = torch::empty({B, GQA_NUM_Q_HEADS},
                          torch::TensorOptions().device(q.device()).dtype(torch::kFloat32));

  launch_gqa_paged_decode_h32_kv8_d128_ps1(
      reinterpret_cast<const __nv_bfloat16*>(q.data_ptr<at::BFloat16>()),
      reinterpret_cast<const __nv_bfloat16*>(k_cache.data_ptr<at::BFloat16>()),
      reinterpret_cast<const __nv_bfloat16*>(v_cache.data_ptr<at::BFloat16>()),
      kv_indptr.data_ptr<int32_t>(),
      kv_indices.data_ptr<int32_t>(),
      sm_scale,
      reinterpret_cast<__nv_bfloat16*>(out.data_ptr<at::BFloat16>()),
      lse.data_ptr<float>(),
      (int32_t)B,
      stream);

  check_cuda(cudaGetLastError(), "CUDA kernel launch failed");
  // Avoid global device sync; sync only this stream.
  check_cuda(cudaStreamSynchronize(stream), "CUDA kernel execution failed");

  return {out, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function",
        py::arg("q"),
        py::arg("k_cache"),
        py::arg("v_cache"),
        py::arg("kv_indptr"),
        py::arg("kv_indices"),
        py::arg("sm_scale") = py::none());
}
